def parse_entity(payload: dict) -> dict:
    return {
        "id": payload.get("id"),
        "name": payload.get("name") or payload.get("nombre"),
        "ok": payload.get("id") is not None,
    }
print(parse_entity({"id": "C001", "nombre": "Ana"}))
print(parse_entity({}))

