cache = {}
def get_cached(key, fetch):
    if key in cache:
        return cache[key], True
    val = fetch()
    cache[key] = val
    return val, False
print(get_cached("C1", lambda: {"id": "C1"}))
print(get_cached("C1", lambda: {"id": "C1"}))

