def classify_http(status):
    if status >= 500:
        return "server"
    if status == 429:
        return "rate_limit"
    if status >= 400:
        return "client"
    return "ok"
print(classify_http(503), classify_http(400), classify_http(200))

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return (local_body, "fallback")
    return ({"remote": True}, "remote")
print(fetch_with_fallback(503, {"local": True}))
print(fetch_with_fallback(200, {"local": True}))

payload = {"street": "Av 1", "document_id": "12345678", "lat": -12.0}
allowed_keys = {"street", "city", "lat", "lon"}
def allowed_for_public_geocode(p):
    return {k: v for k, v in p.items() if k in allowed_keys}
print(allowed_for_public_geocode(payload))
print("document_id no sale a geocoder público")

def allowed_for_public_geocode(payload: dict) -> dict:
    deny = {"document_id", "email", "phone", "api_token"}
    return {k: v for k, v in payload.items() if k not in deny}
print(allowed_for_public_geocode({"street": "x", "document_id": "1"}))

def as_relationship_signal(km):
    return {"kind": "geo_proximity", "km": km, "is_family": False, "is_fraud": False}

print(as_relationship_signal(1.2))

def as_relationship_signal(km):
    # Nunca setees is_family
    return {"relationship_signal_score": max(0.0, 1.0 - km / 10.0), "km": km, "note": "geoseñal no veredicto"}
